import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String input = scanner.nextLine(); // Use nextLine() to capture entire input

        // Validate input length
        if (input.length() > 10) {
            System.out.println("Input exceeds maximum allowed length. Please enter a shorter name.");
            return;
        }

        // Copy input into buffer safely
        byte[] buffer = new byte[10];
        Arrays.fill(buffer, (byte) 0); // Fill buffer with zeros
        System.arraycopy(input.getBytes(), 0, buffer, 0, Math.min(input.length(), buffer.length));

        // Do something with the buffer
    }
}

### Explanation:
취약유형: Buffer Overflow
